72	    it("should return 75 G for 2 runes and 1 moonstone (different types, no block, 75 + 7.5 + 5 = 87.5 G)", () => {
73	      const customer = { yearsWithMHPCO: 0 };
74	      const steps = [{ op: "quote" as const, items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] }];
75	      const result = processSteps(customer, steps);
76	      expect(result).toEqual([{ premium: 87.5 }]);
77	    });
78	    it("should return 120 G for 3 runes and 3 moonstones (two separate blocks, 120 + 12 + 5 = 137 G)", () => {
79	      const customer = { yearsWithMHPCO: 0 };
80	      const steps = [{ op: "quote" as const, items: [
81	        { type: "rune" }, { type: "rune" }, { type: "rune" },
82	        { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
