88	
89	  describe("Quote - item-level modifiers", () => {
90	    it("should add 50% surcharge for a cursed item", () => {
91	      const customer = { yearsWithMHPCO: 0 };
92	      const steps = [{ op: "quote" as const, items: [{ type: "sword", material: "steel", enchantment: 0, cursed: true }] }];
93	      const result = processSteps(customer, steps);
94	      expect(result).toEqual([{ premium: 165 }]);
95	    });
96	    it("should add 30% surcharge for high enchantment (level >= 5)", () => {
97	      const customer = { yearsWithMHPCO: 0 };
98	      const steps = [{ op: "quote" as const, items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }] }];
99	      const result = processSteps(customer, steps);
100	      expect(result).toEqual([{ premium: 145 }]);
101	    });
102	    it("should apply both cursed and high enchantment surcharges to same item", () => {
103	      const customer = { yearsWithMHPCO: 0 };
104	      const steps = [{ op: "quote" as const, items: [{ type: "sword", material: "steel", enchantment: 5, cursed: true }] }];
105	      const result = processSteps(customer, steps);
106	      expect(result).toEqual([{ premium: 195 }]);
107	    });
108	  });
109	
110	  describe("Quote - policy-level modifiers", () => {
111	    it("should add 10% first insurance surcharge (each item treated as first insurance)", () => {
112	      const customer = { yearsWithMHPCO: 0 };
113	      const steps = [{ op: "quote" as const, items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }] }];
114	      const result = processSteps(customer, steps);
115	      expect(result).toEqual([{ premium: 115 }]);
116	    });
117	    it("should apply -20% loyalty discount for long-standing customer (>= 2 years)", () => {
118	      const customer = { yearsWithMHPCO: 3 };
119	      const steps = [{ op: "quote" as const, items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }] }];
120	      const result = processSteps(customer, steps);
121	      expect(result).toEqual([{ premium: 95 }]);
122	    });
123	    it("should apply -15% follow-up discount for each contract after the first", () => {
124	      const customer = { yearsWithMHPCO: 0 };
125	      const steps = [
126	        { op: "quote" as const, items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }] },
127	        { op: "quote" as const, items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }] },
128	      ];
129	      const result = processSteps(customer, steps);
130	      expect(result).toEqual([{ premium: 115 }, { premium: 100 }]);
131	    });
132	  });
133	
134	  describe("Quote - rounding and integration", () => {
135	    it.todo("should round final premium up in MHPCO's favor");
136	    it.todo("should compute newcomer cursed sword as 165 G");
137	    it.todo("should compute long-standing customer second contract cursed sword enchantment 7 as 160 G");
138	  });
139	
140	  describe("Claim - basic processing", () => {
141	    it.todo("should subtract 100 G deductible from damage amount");
142	    it.todo("should cap total payout at 2x insurance sum");
143	    it.todo("should return remaining cap after a claim");
144	  });
145	
146	  describe("Claim - special reimbursement rules", () => {
147	    it.todo("should reimburse at 50% for enchantment >= 8");
148	    it.todo("should fully reimburse for dragon material");
149	    it.todo("should apply 50% when both dragon material and enchantment >= 8");
150	    it.todo("should fully reimburse for dragon material with enchantment < 8, then deductible");
151	  });
152	
153	  describe("Error handling", () => {
154	    it.todo("should reject claim referencing an item not in the policy");
155	    it.todo("should reject negative damage amount");
156	    it.todo("should reject more damage entries of a type than policy covers");
157	  });
158	});
