1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	interface Customer {
13	  yearsWithMHPCO: number;
14	}
15	
16	interface QuoteResult {
17	  premium: number;
18	}
19	
20	const COMPONENT_BLOCK_SIZE = 3;
21	const COMPONENT_BLOCK_PRICE = 60;
22	
23	interface Item {
24	  type: string;
25	  enchantment?: number;
26	  cursed?: boolean;
27	}
28	
29	const CURSED_SURCHARGE_RATE = 0.5;
30	const HIGH_ENCHANTMENT_THRESHOLD = 5;
31	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
32	const FIRST_INSURANCE_RATE = 0.1;
33	const LOYALTY_THRESHOLD = 2;
34	const LOYALTY_DISCOUNT_RATE = 0.2;
35	
36	const basePremiumFor = (type: string): number => BASE_PREMIUMS[type] ?? 0;
37	
38	const itemSurcharge = (item: Item): number => {
39	  const base = basePremiumFor(item.type);
40	  const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
41	  const enchantmentSurcharge =
42	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
43	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
44	      : 0;
45	  return cursedSurcharge + enchantmentSurcharge;
46	};
47	
48	const countByType = (items: Array<Item>): Record<string, number> => {
49	  const counts: Record<string, number> = {};
50	  for (const item of items) {
51	    counts[item.type] = (counts[item.type] ?? 0) + 1;
52	  }
53	  return counts;
54	};
55	
56	const policyBasePremiumFor = (items: Array<Item>): number => {
57	  const typeCounts = countByType(items);
58	  let total = 0;
59	  for (const [type, count] of Object.entries(typeCounts)) {
60	    if (count === COMPONENT_BLOCK_SIZE) {
61	      total += COMPONENT_BLOCK_PRICE;
62	    } else {
63	      total += count * basePremiumFor(type);
64	    }
65	  }
66	  return total;
67	};
68	
69	const quotePremium = (customer: Customer, items: Array<Item>): number => {
70	  const policyBasePremium = policyBasePremiumFor(items);
71	  const totalSurcharges = items.reduce((sum, item) => sum + itemSurcharge(item), 0);
72	  const firstInsurance = policyBasePremium * FIRST_INSURANCE_RATE;
73	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_THRESHOLD
74	    ? policyBasePremium * LOYALTY_DISCOUNT_RATE
75	    : 0;
76	  return policyBasePremium + totalSurcharges + firstInsurance - loyaltyDiscount + PROCESSING_FEE;
77	};
78	
79	export const processSteps = (customer: Customer, steps: Array<{ op: string; items: Array<Item> }>): Array<QuoteResult> =>
80	  steps.map((step) => ({
81	    premium: quotePremium(customer, step.items),
82	  }));
